import React from "react";
import { Link } from "react-router-dom";
import { Error } from "../../components";
import { albums } from "../../musicAlbums";

const AudioAlbum = ({ match }) => {
  const { url } = match;
  const urlSplit = url.split("/")[3];

  // Search for the album for display
  const theAlbum = albums.filter(album => album.title === urlSplit);
  if (theAlbum.length === 0) {
    return <Error />;
  }

  const { title, mp3, zip, folderJPG } = theAlbum[0];
  const mp3Array = Object.entries(mp3);

  return (
    <>
      <section className="section title">
        <h2 className="center">
          <i className="material-icons medium">music_note</i>
          Zion Music
          <i className="material-icons medium">music_note</i>
        </h2>
      </section>
      <section className="sort section">
        <div className="container">
          <Link className="btn" to="/music/">
            <i className="material-icons">navigate_before</i>
          </Link>
          <h4>{title}</h4>
          <div className="row">
            {mp3Array.map(file => (
              <div className="col s12 l6">
                <p>{file[0]}</p>
                <audio controls src={file[1]}></audio>
              </div>
            ))}
          </div>
          <a className="btn" href={zip} download={title}>
            Download Zip
          </a>
        </div>
      </section>
    </>
  );
};

export default AudioAlbum;
