import React from "react";
import { Link } from "react-router-dom";
import Error from "../../components/Error";
import SermonHeading from "../../components/sermon/SermonHeading";
import { s2020, s2019 } from "../../sermons";

const Sermon = ({ match }) => {
  const { url } = match;
  const urlSplit = url.split("/");
  const year = urlSplit[2];
  const urlTitle = urlSplit[3].replace(/-/g, " ");
  let sermonDetails = "";

  if (urlSplit[1] === "sermons") {
    sermonDetails = sermonSearch(year, urlTitle);
  } else {
    sermonDetails = seriesSearch();
  }

  if (sermonDetails === "") {
    return <Error />;
  }

  return (
    <>
      <SermonHeading />
      <section className="section todate">
        <div className="container">
          {sermonDetails.map(sermon => {
            let yearUrl = urlSplit
              .slice(0, urlSplit.length - 1)
              .toString()
              .replace(/,/g, "/");
            let sermonIframe = sermon.audioIframe;
            const sermonDate = sermon.date
              .toDateString()
              .replace(` ${year}`, "");

            let sereiesUrl = `/series/${sermon.series}`;
            return (
              <React.Fragment key={sermon.id}>
                <h4>{sermon.title}</h4>
                <p>
                  {sermonDate}, <Link to={yearUrl}>{` ${year}`}</Link>.
                </p>
                {sermon.series.length > 0 && (
                  <p>
                    Series: <Link to={sereiesUrl}>{sermon.series}</Link>
                  </p>
                )}
                <div>
                  <iframe
                    title={sermon.title}
                    src={sermonIframe.src}
                    width={sermonIframe.width}
                    height={sermonIframe.height}
                  ></iframe>
                </div>
              </React.Fragment>
            );
          })}
        </div>
      </section>
    </>
  );
};

const sermonSearch = (year, title) => {
  // Returns a list of sermons of a particular year
  const yearObject = {
    y2020: s2020,
    y2019: s2019
  };

  const sermonList = yearObject[`y${year}`];
  if (sermonList === undefined) {
    return "";
  }
  const sermon = sermonList.filter(
    sermon => sermon.title.toLowerCase() === title
  );
  if (sermon.length === 0) {
    return "";
  }
  return sermon;
};

const seriesSearch = (series, title) => {
  return "me";
};
export default Sermon;
