import React from "react";
import { Link } from "react-router-dom";
import { teachings } from "../../teachings";
import { Error, TitleSection } from "../../components";

const Article = ({ match }) => {
  const { url } = match;
  const urlSplit = url.split("/")[2];
  // Search for the teaching article
  const article = articleSearch(urlSplit);
  if (article === "") {
    return <Error />;
  }

  return (
    <>
      <TitleSection title="Teachings" />
      <section className="sort section">
        <h3 className="center container">{article.title}</h3>
        <div
          className="container"
          dangerouslySetInnerHTML={{ __html: article.article }}
        ></div>
        <div className="container">
          <Link to="/teachings">
            <i className="material-icons medium">keyboard_arrow_left</i>
          </Link>
        </div>
      </section>
    </>
  );
};

const articleSearch = title => {
  const articleFound = teachings.filter(article => article.title === title);
  if (articleFound.length === 0) {
    return "";
  }
  return articleFound[0];
};

export default Article;
