import React from "react";
import { Link } from "react-router-dom";
import { teachings } from "../../teachings";
import { TitleSection } from "../../components";

const Teachings = () => {
  return (
    <>
      <TitleSection title="Teachings" />
      <section className="sort">
        <div className="container">
          <div className="row">
            {teachings.map((article, no) => {
              no += 1;
              const hide = no % 2 === 0 ? false : true;
              return (
                <React.Fragment key={article.title}>
                  <div className="col s12 m6">
                    <h5>{article.title}</h5>
                    <div
                      dangerouslySetInnerHTML={{ __html: article.intro }}
                    ></div>
                    <Link to={"/teachings/" + article.title} className="btn">
                      Read More
                    </Link>
                  </div>
                  <hr className="col s12" hidden={hide} />
                </React.Fragment>
              );
            })}
          </div>
        </div>
      </section>
    </>
  );
};

export default Teachings;
