import React from "react";
import ReactDOM from "react-dom";
import { HashRouter as Router, Switch, Route } from "react-router-dom";

import "./css/materialize.min.css";
import "./css/main.css";

import { AppBar, ScrollToTop } from "./components";
import {
  Home,
  About,
  Teachings,
  Article,
  Music,
  AudioAlbum,
  Video,
  Sermons,
  Sermon,
  Series,
  Seriess,
  SeriesSermon,
  Footer
} from "./containers";

const App = () => (
  <>
    <AppBar />
    <Main />
    <Footer />
  </>
);

const Main = () => (
  <main>
    <Switch>
      <Route path="/" exact component={Home} />
      <Route path="/home" exact component={Home} />
      <Route path="/about" exact component={About} />

      <Route path="/teachings" exact component={Teachings} />
      <Route path="/teachings/:article" exact component={Article} />

      <Route path="/sermons" exact component={Sermons} />
      <Route path="/sermons/:year" exact component={Sermons} />
      <Route path="/sermons/:year/:title" exact component={Sermon} />
      <Route path="/series" exact component={Seriess} />
      <Route path="/series/:title" exact component={Series} />
      <Route path="/series/:title/:sermon" exact component={SeriesSermon} />

      <Route path="/music" exact component={Music} />
      <Route path="/music/audio/:album" exact component={AudioAlbum} />
      <Route path="/music/videos" exact component={Video} />

      <Route path="" component={Error404} />
    </Switch>
  </main>
);

const Error404 = () => <h3>Kuna chida mahari</h3>;

ReactDOM.render(
  <Router basename={process.env.PUBLIC_URL}>
    <ScrollToTop />
    <App />
  </Router>,
  document.querySelector("#root")
);
