import { sermons as s2020 } from "./s2020";
import { sermons as s2019 } from "./s2019";
import { series, latestSeries } from "./series";

const yearObject = {
  2020: s2020,
  2019: s2019
};

const sermonsWithinArray = (startDate, endDate) => {
  // The start and end dates (years) must be date strings
  const sermonsArray = Object.entries(yearObject).map(year =>
    year[0] >= startDate && year[0] <= endDate ? [...year[1]] : ""
  );
  const returnValue = [];
  sermonsArray.forEach(year => {
    returnValue.push(...year);
  });
  return returnValue;
};

const latestSermon = s2020.sort((a, b) => b.date - a.date)[0];

const latestSermonInSeries = () => {
  const theLatestSeries = latestSeries();
  const seriesTitle = theLatestSeries.title;
  const seriesLatestDate = theLatestSeries.end;
  const getRecentSeriesYear = yearObject[`${seriesLatestDate.getFullYear()}`];
  const latestSermonHere = getRecentSeriesYear
    .filter(sermon => sermon.series === seriesTitle)
    .sort((a, b) => b.date - a.date)[0];

  return latestSermonHere;
};

export {
  s2020,
  s2019,
  series,
  sermonsWithinArray,
  latestSermon,
  latestSermonInSeries
};
