import React from "react";
import { Link } from "react-router-dom";
import { series, sermonsWithinArray } from "../../sermons";
import { Error } from "../../components";
import { SermonHeading } from "../../components/sermon";

const SeriesSermon = ({ match }) => {
  const { url } = match;
  const urlSplit = url.split("/");
  const seriesTitle = urlSplit[2];
  const sermonTitle = urlSplit[3];

  const seriesUrl = `/series/${seriesTitle}`;
  const sermonDetails = sermonSearch(seriesTitle, sermonTitle);

  if (sermonDetails === "") {
    return <Error />;
  }
  const { date, audioIframe } = sermonDetails;
  const yearURL = `/sermons/${date.getFullYear()}`;
  return (
    <>
      <SermonHeading />
      <section className="section todate">
        <div className="container">
          <h4>{sermonDetails.title}</h4>
          <p>
            {date.toDateString().replace(date.getFullYear(), "")},{" "}
            <Link to={yearURL}>{date.getFullYear()}</Link>
          </p>
          <p>
            Series: <Link to={seriesUrl}>{seriesTitle}</Link>
          </p>
          <div>
            <iframe
              title={audioIframe.title}
              src={audioIframe.src}
              width={audioIframe.width}
              height={audioIframe.height}
            ></iframe>
          </div>
        </div>
      </section>
    </>
  );
};

const sermonSearch = (seriesTitle, sermonTitle) => {
  // Fetch the series details
  const seriesDetails = series.filter(sery => seriesTitle === sery.title);

  if (seriesDetails.length === 0) {
    return "";
  }

  // Get the start and end dates
  const { start, end } = seriesDetails[0];
  // Fetch sermons within the dates
  const sermonsWithin = sermonsWithinArray(
    start.getFullYear(),
    end.getFullYear()
  );
  // Filter for the specific sermon
  const sermonDetails = sermonsWithin.filter(
    sermon => sermon.title.toLowerCase().replace(/ /g, "-") === sermonTitle
  );

  if (sermonDetails.length === 0) {
    return "";
  }
  return sermonDetails[0];
};

export default SeriesSermon;
