import React from "react";
import { Link } from "react-router-dom";
import Error from "../Error";
import { s2020, s2019 } from "../../sermons";

const yearMap = year => {
  // Returns a list of sermons of a particular year
  const yearObj = {
    y2020: s2020,
    y2019: s2019
  };

  const yearObjKeys = Object.entries(yearObj);
  const sermonList = yearObjKeys.filter(entry => entry[0] === `y${year}`);
  return sermonList;
};

const Year = ({ url }) => {
  const urlSplit = url.split("/");
  let year = urlSplit.splice(urlSplit.length - 1).toString();
  let newUrl = "";
  if (year === "sermons") {
    year = 2020;
    newUrl = `${url}/2020`;
  } else if (year === "") {
    year = 2020;
    newUrl = `${url}/2020`;
  } else {
    newUrl = url;
  }
  const sermonList = yearMap(year);
  if (sermonList.length === 0) {
    return <Error />;
  }
  return (
    <div className="container">
      <h2>{year}</h2>
      <div className="row">
        {sermonList[0][1].map(sermon => {
          const sermonLink = `${newUrl}/${sermon.title
            .toLowerCase()
            .replace(/ /g, "-")}`;
          const sermonDate = sermon.date.toDateString().replace(` ${year}`, "");
          return (
            <div className="col s12 m6" key={sermon.id}>
              <Link to={sermonLink}>{sermon.title}</Link>
              <p>{sermonDate}</p>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Year;
