import React from "react";
import { Link } from "react-router-dom";
import { Error } from "../../components";
import { SermonHeading } from "../../components/sermon";
import { sermonsWithinArray as seriesSearch, series } from "../../sermons";

const Series = ({ match }) => {
  const { url } = match;
  const urlSplit = url.split("/")[2];
  const seriesSermons = sermonsInSeries(urlSplit);

  if (seriesSermons === "") {
    return <Error />;
  }
  return (
    <>
      <SermonHeading />
      <section className="section todate">
        <div className="container">
          <h4>{urlSplit}</h4>
          <div className="row">
            {seriesSermons.map((sermon, no) => {
              const sermonUrl = `/series/${urlSplit}/${sermon.title
                .toLowerCase()
                .replace(/ /g, "-")}`;
              return (
                <div className="col s12 m4" key={sermon.title}>
                  <Link to={sermonUrl}>
                    {no + 1}-{sermon.title}
                  </Link>
                </div>
              );
            })}
          </div>
        </div>
      </section>
    </>
  );
};

const sermonsInSeries = title => {
  // Get the start and end dates
  const seriesFind = series.filter(sery => sery.title === title);

  // When series is not found
  if (seriesFind.length === 0) {
    return "";
  }
  const { start, end } = seriesFind[0];
  // Get an array of sermons within those dates
  const seriesRange = seriesSearch(start.getFullYear(), end.getFullYear());
  // Filter to get the sermons in the series
  const sermonsInSeries = seriesRange.filter(sermon => sermon.series === title);

  if (sermonsInSeries.length === 0) {
    return "";
  }
  return sermonsInSeries;
};

export default Series;
